import json, glob
try:
    # Evaluation status (DONE phase)
    with open('results/run_summary.json') as f:
        summary = json.load(f)
    rates = {}
    for sweep in summary.get('sweeps', []):
        if sweep.get('domain_pass_rates'):
            rates = sweep['domain_pass_rates']
    passing = sum(1 for v in rates.values() if v >= 0.5)
    total = len(rates)
    # Adapter training status
    adapters = set(p.split('/')[-1].split('_adapter')[0].split('_stage')[0].split('_orthogonal')[0] for p in glob.glob('adapters/*.npz'))
    best = {}
    for name, rate in rates.items():
        base = name.replace('_v2','').replace(' V2','')
        if base not in best or rate > best[base]:
            best[base] = rate
    failing = [b for b, r in best.items() if r < 0.5]
    with_adapter = sum(1 for f in failing if f.replace(' ','_').lower() in adapters or any(f.replace(' ','_').lower() in a for a in adapters))
    msg = f'Eval DONE: {passing}/{total} pass | Adapters: {with_adapter}/{len(failing)} failing domains have adapters'
    # Check escalations
    esc_count = 0
    esc_summary = ''
    try:
        with open('results/escalations.jsonl') as ef:
            for line in ef:
                e = json.loads(line)
                if e.get('status') == 'open':
                    esc_count += 1
                    if esc_count <= 2:
                        esc_summary += f' | ESC: {e["domain"]} — {e["reason"]}'
    except FileNotFoundError:
        pass
    if esc_count > 0:
        msg += f' | {esc_count} escalation(s){esc_summary}'
    print(json.dumps({'hookSpecificOutput': {'hookEventName': 'UserPromptSubmit', 'additionalContext': msg}}))
except Exception:
    pass
" 2>/dev/null || true
